import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';

const AiPage = () => {
  const { id } = useParams();
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  // 根据课程ID设置系统角色提示 (用中文更友好)
  const systemPrompts = {
    1: "你是一名网络安全专家，专门教授密码安全知识。请用简单易懂的语言和表情符号向青少年解释概念。",
    2: "你是一名反钓鱼诈骗专家，需要用清晰的案例教用户识别可疑邮件。",
    3: "你是一名移动安全顾问，需要讲解手机防盗和防病毒的最佳实践。",
    4: "你是一名社交媒体隐私专家，指导用户安全分享内容和设置隐私。",
    5: "你是一名网页安全专家，教用户识别安全网站和避免下载陷阱。"
  };

  // 初始化欢迎消息 (中英混合更自然)
  useEffect(() => {
    const welcomeMessages = {
      1: "👋 你好！我是密码安全小助手，可以问我关于强密码、双重认证等问题哦！",
      2: "🛡️ 你好呀！我是反钓鱼助手，可以发可疑邮件给我帮你分析~",
      3: "📱 嗨！我是手机安全管家，咨询防盗/应用安全等问题都可以！",
      4: "👥 欢迎咨询社交媒体安全问题，我会教你保护隐私~",
      5: "🌐 你好！我是网页安全检测员，可以帮你识别危险网站！"
    };
    
    // 尝试从本地存储加载历史记录
    const savedChat = localStorage.getItem(`chat_${id}`);
    if (savedChat) {
      setMessages(JSON.parse(savedChat));
    } else {
      setMessages([{ 
        role: 'assistant', 
        content: welcomeMessages[id] || "👋 你好！我是网络安全助手，有什么可以帮您？" 
      }]);
    }
  }, [id]);

  // 提交问题处理
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    // 添加用户消息
    const userMessage = { role: 'user', content: input };
    const updatedMessages = [...messages, userMessage];
    setMessages(updatedMessages);
    setInput('');
    setIsLoading(true);
    setError(null);

    try {
      // 调用阿里云API
      const response = await fetchBailianResponse(input, systemPrompts[id]);
      
      // 添加AI回复
      setMessages([...updatedMessages, { 
        role: 'assistant', 
        content: response || "抱歉，我暂时无法处理这个请求，请稍后再试~" 
      }]);
    } catch (err) {
      console.error('API调用失败:', err);
      setError(err.message);
      setMessages([...updatedMessages, { 
        role: 'assistant', 
        content: "⚠️ 连接服务失败: " + (err.message || "请检查网络后重试") 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  // 实际API调用函数 (需替换为你的真实API密钥)
  const fetchBailianResponse = async (userInput, systemPrompt) => {
    const API_KEY = process.env.REACT_APP_DASHSCOPE_API_KEY; 
    const API_URL = 'https://dashscope.aliyun.com/api/v1/services/aigc/text-generation/generation';

    const response = await fetch(API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${API_KEY}`
      },
      body: JSON.stringify({
        model: "qwen-turbo",
        input: {
          messages: [
            { role: "system", content: systemPrompt },
            { role: "user", content: userInput }
          ],
          // 增加参数使回复更自然
          parameters: {
            temperature: 0.8,
            top_p: 0.9
          }
        }
      })
    });

    if (!response.ok) {
      const errData = await response.json();
      throw new Error(errData.message || `API错误: ${response.status}`);
    }
    
    const data = await response.json();
    return data.output.text;
  };

  // 聊天消息自动保存
  useEffect(() => {
    if (messages.length > 1) {
      localStorage.setItem(`chat_${id}`, JSON.stringify(messages));
    }
  }, [messages, id]);

  /* ========== 样式部分 ========== */
  const styles = {
    container: {
      padding: '20px',
      maxWidth: '800px',
      margin: '0 auto',
      fontFamily: '"PingFang SC", "Microsoft YaHei", sans-serif'
    },
    title: {
      textAlign: 'center',
      color: '#1890ff',
      marginBottom: '20px',
      fontSize: '22px',
      fontWeight: '600'
    },
    chatContainer: {
      border: '1px solid #e8e8e8',
      borderRadius: '12px',
      overflow: 'hidden',
      boxShadow: '0 2px 10px rgba(0,0,0,0.05)'
    },
    messages: {
      height: '60vh',
      padding: '15px',
      overflowY: 'auto',
      backgroundColor: '#fafafa'
    },
    messageBubble: (role) => ({
      maxWidth: '85%',
      padding: '12px 16px',
      borderRadius: role === 'user' 
        ? '18px 18px 0 18px' 
        : '18px 18px 18px 0',
      backgroundColor: role === 'user' ? '#1890ff' : '#fff',
      color: role === 'user' ? '#fff' : '#333',
      boxShadow: '0 1px 2px rgba(0,0,0,0.1)',
      marginBottom: '12px',
      alignSelf: role === 'user' ? 'flex-end' : 'flex-start'
    }),
    inputArea: {
      display: 'flex',
      padding: '15px',
      borderTop: '1px solid #eee',
      backgroundColor: '#fff'
    },
    input: {
      flex: 1,
      padding: '12px 15px',
      border: '1px solid #d9d9d9',
      borderRadius: '20px',
      fontSize: '15px',
      outline: 'none',
      transition: 'all 0.3s',
      '&:focus': {
        borderColor: '#1890ff',
        boxShadow: '0 0 0 2px rgba(24,144,255,0.2)'
      }
    },
    submitBtn: {
      marginLeft: '12px',
      padding: '0 24px',
      backgroundColor: '#1890ff',
      color: '#fff',
      border: 'none',
      borderRadius: '20px',
      cursor: 'pointer',
      fontSize: '15px',
      height: '40px',
      transition: 'all 0.3s',
      '&:hover': {
        backgroundColor: '#40a9ff'
      },
      '&:disabled': {
        backgroundColor: '#bae7ff',
        cursor: 'not-allowed'
      }
    },
    typingIndicator: {
      display: 'inline-block',
      '& span': {
        display: 'inline-block',
        width: '8px',
        height: '8px',
        borderRadius: '50%',
        backgroundColor: '#999',
        margin: '0 3px',
        animation: 'bounce 1.4s infinite ease-in-out',
        '&:nth-child(2)': {
          animationDelay: '0.2s'
        },
        '&:nth-child(3)': {
          animationDelay: '0.4s'
        }
      }
    }
  };

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>💬 网络安全助手 - 第 {id} 课</h2>
      
      {/* 错误提示 */}
      {error && (
        <div style={{
          padding: '10px',
          background: '#fff2f0',
          border: '1px solid #ffccc7',
          borderRadius: '4px',
          color: '#f5222d',
          marginBottom: '15px'
        }}>
          {error}
        </div>
      )}

      {/* 聊天区域 */}
      <div style={styles.chatContainer}>
        <div style={styles.messages}>
          {messages.map((msg, i) => (
            <div key={i} style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: msg.role === 'user' ? 'flex-end' : 'flex-start'
            }}>
              <div style={styles.messageBubble(msg.role)}>
                {msg.content.split('\n').map((line, idx) => (
                  <span key={idx}>
                    {line}
                    <br />
                  </span>
                ))}
              </div>
            </div>
          ))}
          
          {/* 加载指示器 */}
          {isLoading && (
            <div style={{...styles.messageBubble('assistant'), color: '#666'}}>
              <div style={styles.typingIndicator}>
                <span></span>
                <span></span>
                <span></span>
              </div>
            </div>
          )}
        </div>

        {/* 输入区域 */}
        <form onSubmit={handleSubmit} style={styles.inputArea}>
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="输入您的问题..."
            style={styles.input}
            disabled={isLoading}
          />
          <button
            type="submit"
            style={{
              ...styles.submitBtn,
              ...(isLoading ? styles.submitBtn['&:disabled'] : {})
            }}
            disabled={isLoading}
          >
            {isLoading ? '发送中...' : '发送'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default AiPage;
